import{_ as t,o,c as a,a2 as i}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Chapter 3: The Agentic Loop","description":"Implement the core loop pattern that transforms a simple chatbot into an autonomous coding agent.","frontmatter":{"title":"Chapter 3: The Agentic Loop","description":"Implement the core loop pattern that transforms a simple chatbot into an autonomous coding agent."},"headers":[],"relativePath":"learn/project/03-the-agentic-loop/index.md","filePath":"learn/project/03-the-agentic-loop/index.md"}'),n={name:"learn/project/03-the-agentic-loop/index.md"};function l(s,e,r,h,c,p){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="the-agentic-loop" tabindex="-1">The Agentic Loop <a class="header-anchor" href="#the-agentic-loop" aria-label="Permalink to &quot;The Agentic Loop&quot;">​</a></h1><p>This chapter introduces the most important architectural pattern in the entire book: the agentic loop. A chatbot sends one message and gets one reply. An agent, by contrast, runs a loop -- it sends a prompt, receives a response that may include tool-use requests, executes those tools, feeds the results back as observations, and repeats until the task is complete or a stop condition is met.</p><p>You will build this loop from scratch in Rust. The implementation starts simple -- a while loop with a match statement -- but the design decisions you make here ripple through every later chapter. You will learn how to manage conversation state as a growing vector of messages, how to detect when the model wants to call a tool versus when it wants to respond to the user, and how to decide when the loop should stop.</p><p>By the end of this chapter your agent will be able to carry on multi-turn conversations and, critically, it will have the scaffolding to execute tools in the next chapter. The loop itself is tool-agnostic; it simply knows that some assistant responses require action and observation before continuing.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Understand the prompt-call-execute-observe cycle that defines agentic behavior</li><li>Implement a loop that alternates between LLM calls and tool execution</li><li>Manage conversation state as a typed message history</li><li>Distinguish between tool-use responses and end-of-turn responses</li><li>Implement stop conditions based on turn count, token budget, and explicit stop signals</li><li>Debug agentic loops by logging message flow and state transitions</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/03-the-agentic-loop/01-what-is-an-agentic-loop.html">What Is an Agentic Loop</a></li><li><a href="/project/03-the-agentic-loop/02-loop-architecture.html">Loop Architecture</a></li><li><a href="/project/03-the-agentic-loop/03-message-types.html">Message Types</a></li><li><a href="/project/03-the-agentic-loop/04-conversation-state.html">Conversation State</a></li><li><a href="/project/03-the-agentic-loop/05-turn-management.html">Turn Management</a></li><li><a href="/project/03-the-agentic-loop/06-stop-conditions.html">Stop Conditions</a></li><li><a href="/project/03-the-agentic-loop/07-implementing-the-core-loop.html">Implementing the Core Loop</a></li><li><a href="/project/03-the-agentic-loop/08-handling-tool-calls.html">Handling Tool Calls</a></li><li><a href="/project/03-the-agentic-loop/09-observation-feeding.html">Observation Feeding</a></li><li><a href="/project/03-the-agentic-loop/10-single-vs-multi-turn.html">Single vs Multi Turn</a></li><li><a href="/project/03-the-agentic-loop/11-debugging-the-loop.html">Debugging the Loop</a></li><li><a href="/project/03-the-agentic-loop/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 2 completed (working LLM API integration with typed request/response structs)</li><li>Familiarity with Rust enums, pattern matching, and the Result type</li></ul>',10)])])}const m=t(n,[["render",l]]);export{g as __pageData,m as default};
